import pytest
import requests

BASE_URL = "http://banking-api"
ENDPOINT = "/accounts"

@pytest.fixture(autouse=True)
def reset_rate_limit(auth_token):
    <helper_fn: reset_user_rate_limit>(auth_token)
    yield

def test_requests_within_limit_succeed(auth_token, reset_rate_limit):
    headers = {"Authorization": f"Bearer {auth_token}"}
    statuses = []
    for _ in range(59):
        r = requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
        statuses.append(r.status_code)
    assert all(s == 200 for s in statuses), (
        f"Expected all 200, got: {set(statuses)}"
    )
