import pytest
import requests

BASE_URL = "http://banking-api"
ENDPOINT = "/accounts"

@pytest.fixture(autouse=True)
def reset_rate_limit(auth_token):
    <helper_fn: reset_user_rate_limit>(auth_token)
    yield

def test_61st_request_returns_429_with_retry_after(auth_token, reset_rate_limit):
    headers = {"Authorization": f"Bearer {auth_token}"}
    for _ in range(60):
        requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
    overage = requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
    assert overage.status_code == 429, (
        f"Expected 429, got {overage.status_code}"
    )
    retry_after = overage.headers.get("Retry-After")
    assert retry_after is not None, "Retry-After header missing"
    assert int(retry_after) > 0, f"Retry-After must be positive, got {retry_after}"

import pytest
import requests

BASE_URL = "http://banking-api"
ENDPOINT = "/accounts"

@pytest.fixture(autouse=True)
def reset_rate_limit(auth_token):
    <helper_fn: reset_user_rate_limit>(auth_token)
    yield

def test_60th_request_succeeds_61st_fails_boundary(auth_token, reset_rate_limit):
    headers = {"Authorization": f"Bearer {auth_token}"}
    for _ in range(59):
        requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
    boundary = requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
    assert boundary.status_code == 200, (
        f"60th (boundary) request must succeed, got {boundary.status_code}"
    )
    beyond = requests.get(BASE_URL + ENDPOINT, headers=headers, timeout=5)
    assert beyond.status_code == 429, (
        f"61st request must be rejected with 429, got {beyond.status_code}"
    )
    retry_after = beyond.headers.get("Retry-After")
    assert retry_after is not None and int(retry_after) > 0
